create table dirkspzm32.isi_avis_hdr (
    nachricht_ziel             varchar2(80 char) default 'MB050WES' not null enable,
    nachricht_typ              varchar2(15 char) default 'Lieferschein' not null enable,
    daten_empf_werk            varchar2(9 char) default '10005007' not null enable,
    daten_sender_nr            varchar2(9 char) default '12345678A' not null enable,
    nachricht_nr_a             number(*, 5) not null enable,
    nachricht_nr               number(*, 5) not null enable,
    nachricht_datum            date not null enable,
    sped_daten_empf            varchar2(9 char),
    lagerhalter_id             varchar2(1 char) default ' ',
    liefer_kennung             varchar2(1 char) default ' ',
    slb_nr                     varchar2(8 char) not null enable,
    werk_lieferant             varchar2(3 char),
    frachtfuehrer              varchar2(14 char) default 'D AG Abholung' not null enable,
    ff_uebergabe_datum         date default sysdate not null enable,
    brutto_gewicht             number(*, 6) not null enable,
    netto_gewicht              number(*, 6),
    frankatur_schluessel       varchar2(2 char) not null enable,
    spediteur_dfu_schluessel   varchar2(1 char),
    anz_packstuecke            number(*, 0) not null enable,
    transport_partner_nr       varchar2(9 char),
    transportmittel_schluessel varchar2(2 char) not null enable,
    transportmittel_nr         varchar2(25 char) not null enable,
    transportmittel_info_id    varchar2(1 char),
    transportmittel_info       varchar2(8 char),
    eintreff_datum_soll        date,
    lademeter                  varchar2(3 char),
    lkw_art_schluessel         varchar2(1 char),
    lieferschein_nr            varchar2(8 char) not null enable,
    lieferschein_datum         date not null enable,
    abladestelle               varchar2(5 char) not null enable,
    versandart                 varchar2(2 char) not null enable,
    abschluss_bestell_nr       varchar2(12 char),
    vorgang_schluessel         varchar2(2 char),
    werk_kunde                 varchar2(3 char),
    konsignation               number(*, 0),
    waren_empfaenger_nr        varchar2(9 char),
    lagerort_kunde             varchar2(7 char),
    lieferanten_nr             varchar2(9 char) not null enable,
    verbrauchsstelle           varchar2(14 char),
    abruf_nr                   varchar2(4 char),
    besteller                  varchar2(6 char),
    dok_nr_kunde               varchar2(14 char),
    transfer_status            varchar2(3 char) default 'N' not null enable,
    fehler_code                number(*, 5) default 0 not null enable,
    fehler_text                varchar2(255 char),
    erstell_datum              date default sysdate not null enable,
    bearb_datum                date,
    export_datum               date,
    import_datum               date,
    nachricht_ursprg           varchar2(80 char),
    bearbeitungs_status        varchar2(1 char) default 'N' not null enable,
    storno_grund               varchar2(100 char)
);

alter table dirkspzm32.isi_avis_hdr
    add constraint pk_isi_avis_hdr
        primary key ( lieferanten_nr,
                      slb_nr,
                      lieferschein_nr )
            using index enable;


